def sync_group_to_workspace(client, desired_user_ids: set, workspace_id: str):
    """Add missing members and remove departed ones from a workspace."""
    # Current state
    page = client.admin.workspaces.members.list(workspace_id=workspace_id, limit=100)
    current = {m.user_id for m in page.data}

    to_add    = desired_user_ids - current
    to_remove = current - desired_user_ids

    for uid in to_add:
        client.admin.workspaces.members.create(
            workspace_id=workspace_id,
            user_id=uid,
            workspace_role="workspace_developer"
        )
        print(f"  Added  {uid}")

    for uid in to_remove:
        client.admin.workspaces.members.delete(
            workspace_id=workspace_id, user_id=uid
        )
        print(f"  Removed {uid}")

    print(f"Sync done: +{len(to_add)} / -{len(to_remove)}")
